import { randomBytes } from "crypto";

const encKey = randomBytes(8).toString("hex");
const url = "https://luarmor.up.railway.app/api/v1/script-auth";
const bytes = Array.from(Buffer.from(url, "utf8"));
const keyBytes: number[] = [];
for (let i = 0; i < encKey.length; i += 2) {
  keyBytes.push(parseInt(encKey.substring(i, i + 2), 16));
}
const encoded = bytes.map((b, i) => (b ^ keyBytes[i % keyBytes.length]) & 0xff);
const hex = encoded.map(b => b.toString(16).padStart(2, "0")).join("");

console.log("Key:", encKey);
console.log("Encoded (hex):", hex.substring(0, 60) + "...");
console.log("Encoded length:", hex.length);
console.log("URL length:", url.length);

// Simulate the Lua decoder logic
const luaDecode = (e: string, dk: string): string => {
  const k: number[] = [];
  for (let i = 0; i < dk.length; i += 2) {
    k.push(parseInt(dk.substring(i, i + 2), 16));
  }
  let o = "";
  let pos = 1;
  for (let i = 0; i < e.length; i += 2) {
    const ch = parseInt(e.substring(i, i + 2), 16);
    const decoded = (ch ^ k[((pos - 1) % k.length)]) & 0xff;
    o += String.fromCharCode(decoded);
    pos++;
  }
  return o;
};

const decoded = luaDecode(hex, encKey);
console.log("Decoded:", decoded);
console.log("Match:", decoded === url ? "YES" : "NO");

